import type { Board } from '../../engine';

/**
 * Computes 3BV (Bechtel's Board Benchmark Value): the minimum number of left-clicks
 * needed to clear a board (assuming optimal play and chord-free).
 *
 * Algorithm: count flood-fill regions of zero-cells (each counts as one click),
 * then add every non-mine, non-zero cell that isn't adjacent to a zero-region.
 *
 * Complexity: O(rows * cols) — single flood-fill sweep.
 */
export function computeThreeBV(board: Board): number {
  const { rows, cols, cells } = board;
  const n = rows * cols;
  const visited = new Uint8Array(n);
  let bv = 0;

  // Pass 1: flood-fill each zero region; count one per region, mark all touched cells.
  for (let i = 0; i < n; i++) {
    if (visited[i] || cells[i]!.isMine || cells[i]!.count !== 0) continue;
    bv++;
    const stack = [i];
    visited[i] = 1;
    while (stack.length) {
      const idx = stack.pop()!;
      const r = Math.floor(idx / cols);
      const c = idx % cols;
      const cell = cells[idx]!;
      if (cell.count !== 0) continue; // numeric edge: don't expand further
      for (let dr = -1; dr <= 1; dr++) {
        for (let dc = -1; dc <= 1; dc++) {
          if (dr === 0 && dc === 0) continue;
          const nr = r + dr, nc = c + dc;
          if (nr < 0 || nr >= rows || nc < 0 || nc >= cols) continue;
          const nidx = nr * cols + nc;
          if (visited[nidx] || cells[nidx]!.isMine) continue;
          visited[nidx] = 1;
          // Only push zero cells to keep expanding the region; numeric edges stay marked.
          if (cells[nidx]!.count === 0) stack.push(nidx);
        }
      }
    }
  }

  // Pass 2: any non-mine cell not yet covered by a region = its own click.
  for (let i = 0; i < n; i++) {
    if (!visited[i] && !cells[i]!.isMine) bv++;
  }

  return bv;
}
