import { useEffect, useMemo } from 'react';
import { useGameStore } from '../../state/store';
import { useStreakStore } from '../daily/streakStore';
import { computeThreeBV } from '../stats/threeBV';
import { useStatsStore } from '../stats/statsStore';

interface Props {
  onClose: () => void;
  onNewGame: () => void;
}

function formatTime(ms: number): string {
  const totalSec = ms / 1000;
  const m = Math.floor(totalSec / 60);
  const s = totalSec - m * 60;
  if (m === 0) return `${s.toFixed(2)}s`;
  return `${m}:${String(Math.floor(s)).padStart(2, '0')}`;
}

const DIFFICULTY_LABEL: Record<string, string> = {
  lite: 'Lite',
  beginner: 'Beginner',
  intermediate: 'Intermediate',
  expert: 'Expert',
};

/**
 * Win completion modal. Lazy-loaded; mounts ~600ms after win to let the
 * win-wash + confetti play first, then presents the receipt.
 */
export default function WinCelebration({ onClose, onNewGame }: Props) {
  const board = useGameStore((s) => s.board);
  const effectiveDifficulty = useGameStore((s) => s.effectiveDifficulty);
  const noGuess = useGameStore((s) => s.noGuess);
  const degraded = useGameStore((s) => s.currentGameDegraded);
  const gameStartedAt = useGameStore((s) => s.gameStartedAt);
  const gameEndedAt = useGameStore((s) => s.gameEndedAt);
  const dailyStreak = useStreakStore((s) => s.current);
  const noGuessStreak = useStatsStore((s) => s.noGuessStreak);

  const timeMs = (gameStartedAt && gameEndedAt) ? gameEndedAt - gameStartedAt : 0;
  // 3BV/s — board-difficulty-normalized solve speed. Useful for self-comparison.
  // Complexity O(n) over board cells. Memoized so it runs once per win.
  const threeBV = useMemo(() => computeThreeBV(board), [board]);
  const threeBVPerSec = timeMs > 0 ? (threeBV / (timeMs / 1000)).toFixed(2) : '—';
  const provenNoGuess = noGuess && !degraded;

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onClose]);

  return (
    <div
      className="ms-sheet-backdrop ms-wincel-backdrop"
      role="presentation"
      onClick={onClose}
    >
      <div
        className="ms-sheet ms-wincel-sheet"
        onClick={(e) => e.stopPropagation()}
        role="dialog"
        aria-modal="true"
        aria-labelledby="ms-wincel-title"
        data-testid="ms-win-celebration"
      >
        <p className="ms-wincel-eyebrow">Cleared</p>
        <h2 id="ms-wincel-title" className="ms-wincel-title">
          {DIFFICULTY_LABEL[effectiveDifficulty] ?? effectiveDifficulty}
        </h2>

        <div className="ms-wincel-stats">
          <div className="ms-wincel-stat">
            <span className="ms-wincel-stat-value" data-testid="ms-wincel-time">
              {formatTime(timeMs)}
            </span>
            <span className="ms-wincel-stat-label">Time</span>
          </div>
          <div className="ms-wincel-stat">
            <span className="ms-wincel-stat-value" data-testid="ms-wincel-bv">
              {threeBV}
            </span>
            <span className="ms-wincel-stat-label">3BV</span>
          </div>
          <div className="ms-wincel-stat">
            <span className="ms-wincel-stat-value" data-testid="ms-wincel-bvps">
              {threeBVPerSec}
            </span>
            <span className="ms-wincel-stat-label">3BV / s</span>
          </div>
        </div>

        <div className="ms-wincel-badges">
          {provenNoGuess && (
            <span className="ms-wincel-badge" data-kind="noguess">
              Pure deduction · no guesses
            </span>
          )}
          {degraded && (
            <span className="ms-wincel-badge" data-kind="degraded">
              Classic mines (degraded)
            </span>
          )}
          {dailyStreak > 0 && (
            <span className="ms-wincel-badge" data-kind="streak">
              Daily streak · {dailyStreak}
            </span>
          )}
          {noGuessStreak > 1 && (
            <span className="ms-wincel-badge" data-kind="ng-streak">
              No-guess streak · {noGuessStreak}
            </span>
          )}
        </div>

        <div className="ms-wincel-actions">
          <button
            type="button"
            className="ms-wincel-secondary"
            onClick={onClose}
            data-testid="ms-wincel-close"
          >
            Close
          </button>
          <button
            type="button"
            className="ms-wincel-primary"
            onClick={onNewGame}
            data-testid="ms-wincel-new"
          >
            Play again
          </button>
        </div>
      </div>
    </div>
  );
}
